import { MakeLogicType, afterMount, kea, path, reducers, selectors } from 'kea'
import { loaders } from 'kea-loaders'

import api from 'lib/api'
import { retryWithBackoff } from 'lib/utils/async'


const teamId = window.POSTHOG_APP_CONTEXT?.current_team?.id

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsIngestionLogicValues {
    cachedTeamHasLogs: boolean | null;
    hasLogs: boolean | undefined;
    teamHasLogs: boolean | undefined;
    teamHasLogsCheckFailed: boolean;
    teamHasLogsLoading: boolean;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsIngestionLogicActions {
    loadTeamHasLogs: () => any;
    loadTeamHasLogsFailure: (error: string, errorObject?: any) => {
        error: string;
        errorObject?: any;
    };
    loadTeamHasLogsSuccess: (teamHasLogs: boolean, payload?: any) => {
        teamHasLogs: boolean;
        payload?: any;
    };
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface logsIngestionLogicMeta {
    __keaTypeGenInternalSelectorTypes: {
        hasLogs: (teamHasLogs: boolean | undefined, cachedTeamHasLogs: boolean | null) => boolean | undefined;
    };
}

export type logsIngestionLogicType = MakeLogicType<logsIngestionLogicValues, logsIngestionLogicActions, Record<string, any>, logsIngestionLogicMeta>;

export const logsIngestionLogic = kea<logsIngestionLogicType>([
    path(['products', 'logs', 'components', 'SetupPrompt', 'logsIngestionLogic']),
    loaders({
        teamHasLogs: {
            __default: undefined as boolean | undefined,
            loadTeamHasLogs: async (): Promise<boolean> => {
                return await retryWithBackoff(() => api.logs.hasLogs(), { maxAttempts: 3 })
            },
        },
    }),

    reducers({
        teamHasLogsCheckFailed: [
            false,
            {
                loadTeamHasLogs: () => false,
                loadTeamHasLogsSuccess: () => false,
                loadTeamHasLogsFailure: () => true,
            },
        ],
        cachedTeamHasLogs: [
            null as boolean | null,
            { persist: true, prefix: `${teamId}__` },
            {
                // Only cache true - logs don't disappear once ingested
                loadTeamHasLogsSuccess: (_, { teamHasLogs }) => teamHasLogs || null,
            },
        ],
    }),

    selectors({
        hasLogs: [
            (s) => [s.teamHasLogs, s.cachedTeamHasLogs],
            (teamHasLogs: boolean | undefined, cachedTeamHasLogs: boolean | null): boolean | undefined => teamHasLogs ?? cachedTeamHasLogs ?? undefined,
        ],
    }),

    afterMount(({ actions, values }) => {
        if (values.cachedTeamHasLogs !== true) {
            actions.loadTeamHasLogs()
        }
    }),
])
